    String apname=request.getParameter("a");
    String path=request.getParameter("p");
    int sheetIndex= Encoder.parseInt(request.getParameter("si"));
    boolean useFirstNode="true".equals(request.getParameter("useFirstNode"));
    String action=request.getParameter("action");

    //access right check
    User access=(User)session.getAttribute("USER");
    if(access==null || !access.ifApManager(apname)) {
        if(access!=null) out.println("No access for "+access.getUserId());
        else out.println("Not Logged In.");
        return;
    }

    NUIForm form= AppManager.getFormPage(apname, path, sheetIndex);
    if(form==null) return;

//    if("unlink".equals(action)){
