//        }
//        return;
//    }
    if("dedup".equals(action)){
        BDBWorker worker=new BDBWorker(apname);
        List<BDBWorkerCommand> dedups=new ArrayList<>();
        try{
            int key=form.getKeyField();
            SDBQuery q=new SDBQueryFull(worker);
            q.go(key);
            SDBNode keyNode;
            while((keyNode=q.next())!=null){
                for(CellInfo info:form.getAllFields(false)){
                    if(Const.MSELECT.equals(info.getType()) || info.isMultiFilesUpload()) continue;

                    List<SDBNode> list=q.dipAllNodes(info.getDomainId());
                    for(int i=0;i<list.size();i++){
                        int keepIndex=useFirstNode?0:list.size()-1;
                        if(i!=keepIndex) {
                            System.out.println("Dedup for keyNodeId: "+keyNode.getId());
                            dedups.add(new BDBWorkerCommandUnlink(key,keyNode.getId(),info.getDomainId(),list.get(i).getId()));
                        }
                    }
                }
                //do subtables
                Map<CellLocation,Integer> subtableKeys=form.getSubtableKey();
                for(Map.Entry<CellLocation,Integer> e:subtableKeys.entrySet()){
                    Integer subtableKey=e.getValue();
                    List<CellInfo> subtableCellInfoList =form.getSubtableFields(subtableKey);
                    Integer parentAlias=form.getSubtableParentAlias(e.getKey());
                    q.go(e.getValue());
                    if(parentAlias!=null){
                        q.setAliasParent(parentAlias);
                    }
                    SDBNode subtableKeyNode=null;
                    while((subtableKeyNode=q.next())!=null){
                        for(CellInfo info: subtableCellInfoList){
                            if(Const.MSELECT.equals(info.getType()) || info.isMultiFilesUpload()) continue;
                            List<SDBNode> list=q.dipAllNodes(info.getDomainId());
                            for(int i=0;i<list.size();i++){
                                int keepIndex=useFirstNode?0:list.size()-1;
                                if(i!=keepIndex) {
                                    dedups.add(new BDBWorkerCommandUnlink(subtableKey,subtableKeyNode.getId(),info.getDomainId(),list.get(i).getId()));
                                }
                            }
                            out.println("</div>");
                        }
                    }
                    out.println("</div>");
                    q.goback();
                }
            }
        }
        finally{
            worker.commit();
        }
        worker=new BDBWorker(apname);
        try{
            System.out.println("Dedup removing "+dedups.size()+" links for "+apname+path+"/"+sheetIndex);
            for(BDBWorkerCommand c:dedups){
                c.execute(worker);
            }
            System.out.println("Dedup removed "+dedups.size()+" links for "+apname+path+"/"+sheetIndex);
        }
        finally{
            worker.commit();
        }
    }

